/**
 * ејҖе§ӢеҲҶж®өдёӢиҪҪ
 */
suspend fun download(config: DownloadConfig): Result<File> = withContext(Dispatchers.IO) {
    // йҮҚзҪ®еҸ–ж¶Ҳж Үеҝ—
    currentCancellationFlag.set(false)

    try {
        Log.d("SegmentedDownloader", "Starting download: ${config.url}")

        // иҺ·еҸ–ж–Үд»¶еӨ§е°Ҹ
        val fileSize = getContentLength(config.url)
        if (fileSize <= 0) {
            // дёҚж”ҜжҢҒеҲҶж®өдёӢиҪҪпјҢдҪҝз”Ёжҷ®йҖҡдёӢиҪҪ
            Log.d("SegmentedDownloader", "Segmented download not supported, using simple download")
            return@withContext simpleDownload(config)
        }

        Log.d("SegmentedDownloader", "File size: $fileSize bytes (${formatFileSize(fileSize)})")

        // ж №жҚ®ж–Үд»¶еӨ§е°ҸйҖүжӢ©еҗҲйҖӮзҡ„еҲҶж®өеӨ§е°Ҹ
        val actualSegmentSize = if (fileSize >= LARGE_FILE_THRESHOLD) {
            Log.d("SegmentedDownloader", "Large file detected, using larger segment size")
            LARGE_SEGMENT_SIZE
        } else {
            config.segmentSize
        }

        // еҲӨж–ӯжҳҜеҗҰйңҖиҰҒеҲҶж®ө
        if (fileSize < MIN_SEGMENT_SIZE) {
            Log.d("SegmentedDownloader", "File too small for segmentation, using simple download")
            return@withContext simpleDownload(config)
        }

        // и®Ўз®—еҲҶж®өж•°йҮҸ
        val segmentCount = ((fileSize + actualSegmentSize - 1) / actualSegmentSize).toInt()
        Log.d("SegmentedDownloader", "Splitting into $segmentCount segments of ${formatFileSize(actualSegmentSize)} each")

        // еҲӣе»әдёҙж—¶ж–Үд»¶
        val tempFile = File(config.outputFile.absolutePath + ".tmp")

        // еҲқе§ӢеҢ–еҲҶж®өзҠ¶жҖҒ
        val segmentStates = if (config.enableResume) {
            loadResumeState(tempFile, fileSize, actualSegmentSize, segmentCount)
        } else {
            createInitialSegments(fileSize, actualSegmentSize, segmentCount)
        }

        // и®ҫзҪ®дёҙж—¶ж–Үд»¶еӨ§е°Ҹ
        try {
            val raf = RandomAccessFile(tempFile, "rw")
            raf.setLength(fileSize)
            raf.close()
        } catch (e: Exception) {
            Log.e("SegmentedDownloader", "Failed to set temp file size", e)
            // еҰӮжһңж–Үд»¶е·ІеӯҳеңЁдё”еӨ§е°ҸжӯЈзЎ®пјҢз»§з»ӯ
            if (tempFile.length() != fileSize) {
                throw IOException("Failed to initialize temp file")
            }
        }

        // и®Ўз®—е·ІдёӢиҪҪеӯ—иҠӮж•°
        var totalDownloaded = segmentStates.filter { it.isCompleted }
            .sumOf { it.end - it.start + 1 }
        val startTime = System.currentTimeMillis()
        val lastProgressUpdate = AtomicLong(startTime)

        // дҪҝз”Ёе№¶еҸ‘дёӢиҪҪ
        val pendingSegments = segmentStates
            .filterNot { it.isCompleted }
            .map { it.index }
            .toMutableList()

        val completedSegments = segmentStates
            .filter { it.isCompleted }
            .map { it.index }
            .toMutableSet()

        Log.d("SegmentedDownloader", "Resume state loaded: ${completedSegments.size}/$segmentCount segments already completed")

        // еҲҶжү№е№¶еҸ‘дёӢиҪҪ
        val concurrency = minOf(config.concurrentDownloads, pendingSegments.size)
        Log.d("SegmentedDownloader", "Starting concurrent download with $concurrency connections")

        val downloadJobs = (0 until concurrency).mapNotNull { workerIndex ->
            if (pendingSegments.isEmpty()) return@mapNotNull null

            async {
                while (pendingSegments.isNotEmpty() && !currentCancellationFlag.get()) {
                    // жЈҖжҹҘеҸ–ж¶Ҳ
                    if (currentCancellationFlag.get()) {
                        Log.d("SegmentedDownloader", "Download cancelled for worker $workerIndex")
                        break
                    }

                    val segmentIndex = pendingSegments.removeFirstOrNull() ?: break
                    val segment = segmentStates[segmentIndex]

                    try {
                        Log.d("SegmentedDownloader", "Worker $workerIndex downloading segment ${segment.index}: ${segment.start}-${segment.end}")

                        // дёӢиҪҪеҲҶж®ө
                        downloadSegmentWithRetry(
                            config = config,
                            tempFile = tempFile,
                            segment = segment,
                            retries = config.maxRetries,
                            onProgress = { bytesDownloaded, segmentTotal ->
                                // жӣҙж–°еҪ“еүҚеҲҶж®өиҝӣеәҰ
                                val currentTotal = totalDownloaded + completedSegments.size * actualSegmentSize + bytesDownloaded
                                val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
                                val speed = if (elapsed > 0) (currentTotal / elapsed).toLong() else 0
                                val remainingBytes = fileSize - currentTotal
                                val remainingSeconds = if (speed > 0) remainingBytes / speed else 0

                                // йҷҗеҲ¶иҝӣеәҰжӣҙж–°йў‘зҺҮпјҲжҜҸ200msжңҖеӨҡдёҖж¬Ўпјү
                                val now = System.currentTimeMillis()
                                if (now - lastProgressUpdate.get() >= 200 || bytesDownloaded == segmentTotal) {
                                    lastProgressUpdate.set(now)
                                    config.onProgress(DownloadProgress(
                                        bytesDownloaded = currentTotal,
                                        totalBytes = fileSize,
                                        percent = ((currentTotal * 100) / fileSize).toInt(),
                                        speed = speed,
                                        segmentIndex = segment.index + 1,
                                        totalSegments = segmentCount,
                                        completedSegments = completedSegments.toSet(),
                                        currentSegmentBytes = bytesDownloaded,
                                        currentSegmentTotal = segmentTotal,
                                        remainingTimeSeconds = remainingSeconds,
                                        activeConnections = pendingSegments.size + 1
                                    ))
                                }
                            }
                        )

                        // ж Үи®°е®ҢжҲҗ
                        completedSegments.add(segment.index)
                        segmentStates[segment.index] = segment.copy(isCompleted = true)

                        // дҝқеӯҳж–ӯзӮ№зҠ¶жҖҒ
                        saveResumeState(tempFile, fileSize, actualSegmentSize, segmentStates)

                        config.onSegmentComplete(segment.index, true)
                        Log.d("SegmentedDownloader", "Worker $workerIndex completed segment ${segment.index}")

                    } catch (e: Exception) {
                        Log.e("SegmentedDownloader", "Worker $workerIndex failed to download segment ${segment.index}", e)
                        config.onSegmentComplete(segment.index, false)

                        // дҝқеӯҳж–ӯзӮ№зҠ¶жҖҒ
                        saveResumeState(tempFile, fileSize, actualSegmentSize, segmentStates)

                        if (!currentCancellationFlag.get()) {
                            throw e
                        }
                    }

                    // и®©еҮәCPUж—¶й—ҙ
                    yield()
                }
            }
        }

        // зӯүеҫ…жүҖжңүдёӢиҪҪе®ҢжҲҗ
        downloadJobs.forEach { it.await() }

        // жЈҖжҹҘжҳҜеҗҰиў«еҸ–ж¶Ҳ
        if (currentCancellationFlag.get()) {
            Log.d("SegmentedDownloader", "Download was cancelled")
            saveResumeState(tempFile, fileSize, actualSegmentSize, segmentStates)
            return@withContext Result.failure(IOException("Download cancelled"))
        }

        // йӘҢиҜҒдёӢиҪҪе®Ңж•ҙжҖ§
        val expectedCompleted = segmentStates.count { it.isCompleted }
        if (expectedCompleted != segmentCount) {
            throw IOException("Download incomplete: $expectedCompleted/$segmentCount segments completed")
        }

        // йҮҚе‘ҪеҗҚдёәжңҖз»Ҳж–Үд»¶
        if (config.outputFile.exists()) {
            config.outputFile.delete()
        }
        if (!tempFile.renameTo(config.outputFile)) {
            throw IOException("Failed to rename temp file to final file")
        }

        // жё…зҗҶж–ӯзӮ№зҠ¶жҖҒ
        clearResumeState(config.outputFile)

        // жңҖз»ҲиҝӣеәҰжӣҙж–°
        val elapsed = (System.currentTimeMillis() - startTime) / 1000.0
        val avgSpeed = if (elapsed > 0) (fileSize / elapsed).toLong() else 0
        config.onProgress(DownloadProgress(
            bytesDownloaded = fileSize,
            totalBytes = fileSize,
            percent = 100,
            speed = avgSpeed,
            segmentIndex = segmentCount,
            totalSegments = segmentCount,
            completedSegments = completedSegments.toSet(),
            currentSegmentBytes = actualSegmentSize,
            currentSegmentTotal = actualSegmentSize,
            remainingTimeSeconds = 0,
            activeConnections = 0
        ))

        Log.d("SegmentedDownloader", "Download completed: ${config.outputFile.absolutePath} in ${elapsed.toInt()}s")
        Result.success(config.outputFile)
    } catch (e: Exception) {
        Log.e("SegmentedDownloader", "Download failed", e)
        Result.failure(e)
    }
}

